int dp[1 << N][K]; // dp[state][k] 表示状态为state，附加维度为k时的最优解/方案数
// 状态state通常用二进制位表示集合，1表示选中，0表示未选中

// 初始化
dp[0][0] = 初始值; // 空集合的初始状态

// 状态转移
for (int state = 0; state < (1 << N); state++) {
    for (int k = 0; k <= K; k++) {
        if (dp[state][k]无效) continue;
        // 枚举下一个加入集合的元素
        for (int i = 0; i < N; i++) {
            if (state >> i & 1) continue; // 已存在则跳过
            int new_state = state | (1 << i);
            // 根据题意更新dp[new_state][new_k]
            // 例如：dp[new_state][new_k] = min(dp[new_state][new_k], dp[state][k] + cost);
        }
    }
}

