// 位运算辅助函数
int getBit(int x, int k) { return (x >> k) & 1; }
int setBit(int x, int k) { return x | (1 << k); }

// 数据结构操作
void insert(Node* root, int x) {
    // 在Trie/线段树中插入值x
    for (int i = MAX_BIT; i >= 0; i--) {
        int b = getBit(x, i);
        if (b == 0) {
            if (!root->left) root->left = new Node();
            root = root->left;
        } else {
            if (!root->right) root->right = new Node();
            root = root->right;
        }
        root->val++; // 更新计数或其他信息
    }
}

int query(Node* root, int x) {
    // 查询与x相关的最大/最小值（如最大异或）
    int res = 0;
    for (int i = MAX_BIT; i >= 0; i--) {
        int b = getBit(x, i);
        if (b == 0 && root->right) {
            res = setBit(res, i);
            root = root->right;
        } else if (b == 1 && root->left) {
            res = setBit(res, i);
            root = root->left;
        } else {
            // 根据实际情况调整路径选择
            root = (root->left ? root->left : root->right);
        }
    }
    return res;
}

// 线段树区间更新/查询（适用于位运算区间操作）
void updateSeg(int node, int l, int r, int ql, int qr, int val) {
    if (ql <= l && r <= qr) {
        // 根据位运算性质更新节点（如区间异或）
        tree[node] ^= val;
        lazy[node] ^= val;
        return;
    }
    pushDown(node);
    int mid = (l + r) >> 1;
    if (ql <= mid) updateSeg(node<<1, l, mid, ql, qr, val);
    if (qr > mid) updateSeg(node<<1|1, mid+1, r, ql, qr, val);
    tree[node] = tree[node<<1] | tree[node<<1|1]; // 按需合并（如按位或）
}

