int solve() {
    int ans = 0;
    // 从高位向低位贪心
    for (int bit = MAX_BIT; bit >= 0; bit--) {
        // 尝试将ans的当前位设为1
        int candidate = ans | (1 << bit);
        // 检查是否存在满足条件的数对/序列使得当前位能为1
        if (check(candidate)) {
            ans = candidate; // 保留该位为1
        }
        // 否则该位保持为0
    }
    return ans;
