    if (need_split(x, y, k)) {
        // 递归处理四个子区域
        dfs(k-1, x, y);
        dfs(k-1, x | (1<<k), y);
        dfs(k-1, x, y | (1<<k));
        dfs(k-1, x | (1<<k), y | (1<<k));
    } else {
        // 统计当前区域的贡献
        update_answer(x, y, k);
    }
}

class BlockDecompose {
    int n, blockSize, blockCount;
    vector<int> arr;
    vector<vector<int>> blocks;

    void build() {
        blockSize = sqrt(n);
        blockCount = (n + blockSize - 1) / blockSize;
        blocks.resize(blockCount);
        for (int i = 0; i < n; i++) {
            blocks[i / blockSize].push_back(arr[i]);
        }
    }

    pair<int, int> getPosition(int pos) {
        int blockIdx = 0;
        while (pos >= blocks[blockIdx].size()) {
            pos -= blocks[blockIdx].size();
            blockIdx++;
        }
        return {blockIdx, pos};
    }

    void insert(int pos, int val) {
        auto [blockIdx, offset] = getPosition(pos);
        blocks[blockIdx].insert(blocks[blockIdx].begin() + offset, val);
        if (blocks[blockIdx].size() > 2 * blockSize) {
            rebalance(blockIdx);
        }
    }

    void erase(int pos) {
        auto [blockIdx, offset] = getPosition(pos);
        blocks[blockIdx].erase(blocks[blockIdx].begin() + offset);
        if (blocks[blockIdx].empty()) {
            blocks.erase(blocks.begin() + blockIdx);
            blockCount--;
        }
    }

    void rebalance(int blockIdx) {
        vector<int> temp;
        for (int i = blockIdx; i < blockCount; i++) {
            temp.insert(temp.end(), blocks[i].begin(), blocks[i].end());
        }
        blocks.resize(blockIdx + 1);
        int start = 0;
        for (int i = blockIdx; i < blockCount; i++) {
            int end = min(start + blockSize, (int)temp.size());
            blocks[i].assign(temp.begin() + start, temp.begin() + end);
            start = end;
        }
        if (start < temp.size()) {
            blocks.push_back(vector<int>(temp.begin() + start, temp.end()));
            blockCount++;
        }
    }

    int query(int l, int r, int k) {
        auto [blockL, offsetL] = getPosition(l);
        auto [blockR, offsetR] = getPosition(r);
        int ans = 0;
        if (blockL == blockR) {
            for (int i = offsetL; i <= offsetR; i++) {
                if (blocks[blockL][i] == k) ans++;
            }
        } else {
            for (int i = offsetL; i < blocks[blockL].size(); i++) {
                if (blocks[blockL][i] == k) ans++;
            }
            for (int i = 0; i <= offsetR; i++) {
                if (blocks[blockR][i] == k) ans++;
            }
            for (int i = blockL + 1; i < blockR; i++) {
                ans += count(blocks[i].begin(), blocks[i].end(), k);
            }
        }
        return ans;
    }
};

