// 主函数框架
void parallel_binary_search(int low, int high, vector<Query>& active_queries) {
    if (low == high) {
        for (auto& q : active_queries) q.ans = low;
        return;
    }
    int mid = (low + high) / 2;

    // 1. 处理当前批次的 mid 值：更新数据结构（如树状数组、线段树）
    //    通常根据 mid 值添加/删除某些元素或操作
    update_data_structure(mid);

    // 2. 对每个活跃查询进行判定
    vector<Query> left_queries, right_queries;
    for (auto& q : active_queries) {
        if (check_query(q, mid)) { // 检查条件是否满足
            left_queries.push_back(q); // 答案在 [low, mid]
        } else {
            right_queries.push_back(q); // 答案在 [mid+1, high]
        }
    }

    // 3. 恢复数据结构到更新前的状态（回溯）
    rollback_data_structure(mid);

    // 4. 递归处理左右两部分
    parallel_binary_search(low, mid, left_queries);
    parallel_binary_search(mid+1, high, right_queries);
}

