// 对区间 [l, r] (0-indexed) 增加 val
void rangeAdd(vector<int>& diff, int l, int r, int val) {
    diff[l] += val;
    if (r + 1 < diff.size()) diff[r + 1] -= val;
}

// 从差分数组恢复原数组
vector<int> restoreArray(const vector<int>& diff, int n) {
    vector<int> arr(n);
    arr[0] = diff[0];
    for (int i = 1; i < n; i++) {
        arr[i] = arr[i - 1] + diff[i];
    }
    return arr;
}

