void init_pow(int n) {
    pow_base.resize(n+1);
    pow_base[0] = 1;
    for (int i=1; i<=n; i++) 
        pow_base[i] = pow_base[i-1] * BASE % MOD;
}

// DFS预处理树信息
void dfs(int u, int p, ull hash_up, ull hash_down, int dep) {
    parent[u] = p;
    depth[u] = dep;
    tin[u] = ++timer;
    path_hash_up[u] = hash_up;
    path_hash_down[u] = hash_down;

    for (auto &[v, c] : g[u]) {
        if (v == p) continue;
        ull new_up = (hash_up * BASE + c) % MOD;
        ull new_down = (hash_down + c * pow_base[dep]) % MOD;
        dfs(v, u, new_up, new_down, dep+1);
    }
    tout[u] = timer;
}

