// 字符串哈希模板（双哈希，减少冲突）
struct StringHash {
    using ull = unsigned long long;
    const int P1 = 131, P2 = 13331;
    const ull MOD1 = 1e9 + 7, MOD2 = 1e9 + 9;
    vector<ull> h1, h2, p1, p2;

    // 初始化哈希表
    void init(const string &s) {
        int n = s.size();
        h1.resize(n + 1); h2.resize(n + 1);
        p1.resize(n + 1); p2.resize(n + 1);
        p1[0] = p2[0] = 1;
        for (int i = 1; i <= n; i++) {
            h1[i] = (h1[i - 1] * P1 + s[i - 1]) % MOD1;
            h2[i] = (h2[i - 1] * P2 + s[i - 1]) % MOD2;
            p1[i] = p1[i - 1] * P1 % MOD1;
            p2[i] = p2[i - 1] * P2 % MOD2;
        }
    }

    // 获取子串 [l, r] 的双哈希值（0-indexed）
    pair<ull, ull> get_hash(int l, int r) {
        ull hash1 = (h1[r + 1] - h1[l] * p1[r - l + 1] % MOD1 + MOD1) % MOD1;
        ull hash2 = (h2[r + 1] - h2[l] * p2[r - l + 1] % MOD2 + MOD2) % MOD2;
        return {hash1, hash2};
    }
};

