// 数据结构定义
typedef pair<int, int> PII;
multiset<PII> segments; // 存储所有线段
multiset<int> left_ends; // 所有左端点
multiset<int> right_ends; // 所有右端点

// 添加线段操作
void add_segment(int l, int r) {
    segments.insert({l, r});
    left_ends.insert(l);
    right_ends.insert(r);
}

// 删除线段操作
void remove_segment(int l, int r) {
    segments.erase(segments.find({l, r}));
    left_ends.erase(left_ends.find(l));
    right_ends.erase(right_ends.find(r));
}

// 查询是否存在覆盖所有线段的公共点
bool has_common_point() {
    if (segments.empty()) return true; // 无线段时视为有公共点
    int max_left = *left_ends.rbegin(); // 所有左端点的最大值
    int min_right = *right_ends.begin(); // 所有右端点的最小值
    return max_left <= min_right; // 存在公共点当且仅当 max_left ≤ min_right
}

