    long long time;  // 时间相关参数（到达时间/截止时间/处理时间）
    int priority;    // 优先级（可选）
    // 可根据题目添加其他字段
    bool operator<(const Task& other) const {
        // 根据题目要求定义优先级比较规则
        // 常见：优先级高的先处理，时间小的先处理
        if (priority != other.priority)
            return priority < other.priority; // 大顶堆
        return time > other.time; // 时间小的优先
    }
};

