// 延迟处理与懒删除通用模板
// 核心数据结构：优先队列（堆）配合懒删除标记
// 适用场景：需要动态维护最大值/最小值，且元素可能被删除

template<typename T>
struct LazyHeap {
    priority_queue<T> active;          // 当前活跃元素
    priority_queue<T> deleted;         // 标记为删除的元素

    // 添加元素
    void push(T x) {
        active.push(x);
    }

    // 标记删除元素（延迟删除）
    void erase(T x) {
        deleted.push(x);
    }

    // 获取堆顶元素（清理已删除的）
    T top() {
        clean();
        return active.top();
    }

    // 弹出堆顶元素（清理已删除的）
    void pop() {
        clean();
        active.pop();
    }

    // 清理堆顶已删除的元素
    void clean() {
        while (!active.empty() && !deleted.empty() && 
               active.top() == deleted.top()) {
            active.pop();
            deleted.pop();
        }
    }

    // 判断是否为空
    bool empty() {
        clean();
        return active.empty();
    }
};

