int main() {
    // 1. 读取输入数据
    int n, m;
    cin >> n >> m;
    vector<int> actions(m);
    for (int i = 0; i < m; i++) cin >> actions[i];

    // 2. 初始化数据结构
    // 使用集合/哈希表记录当前显示的内容
    set<int> displayed;
    for (int i = 1; i <= n; i++) displayed.insert(i);

    // 3. 处理每个动作
    vector<int> result(n, -1);  // 记录每个位置第一次被替换的时间
    int time = 0;

    for (int action : actions) {
        time++;

        // 4. 贪心策略：总是替换最久未访问/最不可能再需要的元素
        // 这里的具体策略根据题目而定
        if (displayed.find(action) == displayed.end()) {
            // 需要替换一个已显示的内容
            // 选择策略：通常替换最久未使用的或根据某种优先级
            int to_remove = *displayed.begin();  // 示例：替换最小的

            // 记录被替换的内容和替换时间
            result[to_remove - 1] = time;

            // 更新显示集合
            displayed.erase(to_remove);
            displayed.insert(action);
        }
        // 如果action已经在显示中，可能需要更新其状态（如LRU策略）
    }

    // 5. 输出结果
    for (int i = 0; i < n; i++) {
