    return 0;
}

class WeightedDSU {
    vector<int> parent, size;
    vector<long long> weight; // 或 vector<int>，根据题目需要
    // weight[x] 表示 x 到其父节点的权值（如距离、异或值、集合标识等）
    // 在路径压缩后，weight[x] 表示 x 到根节点的权值
public:
    WeightedDSU(int n) : parent(n), size(n, 1), weight(n, 0) {
        iota(parent.begin(), parent.end(), 0);
    }

    int find(int x) {
        if (parent[x] != x) {
            int root = find(parent[x]);
            weight[x] += weight[parent[x]]; // 或 weight[x] ^= weight[parent[x]] 等，根据运算性质
            parent[x] = root;
        }
        return parent[x];
    }

    // 合并 x 和 y，并指定它们之间的权值关系（如 w = val[x] - val[y] 或 val[x] ^ val[y]）
    bool unite(int x, int y, long long w) {
        int rx = find(x), ry = find(y);
        if (rx == ry) {
            // 检查现有关系是否与 w 一致，若冲突则返回 false（如形成矛盾）
            return (weight[x] - weight[y]) == w; // 根据具体运算调整
        }
        // 按秩合并，调整权值
        if (size[rx] < size[ry]) {
            swap(rx, ry);
            swap(x, y);
            w = -w; // 或根据运算性质调整
        }
        parent[ry] = rx;
        weight[ry] = weight[x] - weight[y] - w; // 关键：根据运算性质推导
        size[rx] += size[ry];
        return true;
    }

    // 获取 x 和 y 之间的权值关系（如差值、异或值）
    long long diff(int x, int y) {
        if (find(x) != find(y)) return LLONG_MAX; // 或不连通
        return weight[x] - weight[y]; // 或 weight[x] ^ weight[y]
    }
};

