        // 更新并查集结构
        parent[y] = x;
        size[x] += size[y];
        // 可能需要在合并后触发全局更新或答案计算
    }

    // 根据题目需求，可能添加查询集合信息的函数
    int get_info(int x) {
        return comp_info[find(x)];
    }
};

