            prev[i] = i - 1;
            val[i] = init_val; // 初始化
        }
    }

    int find(int x) {
        return parent[x] == x ? x : parent[x] = find(parent[x]);
    }

    // 合并两个相邻区间/节点
    void merge(int x, int y) {
        int fx = find(x), fy = find(y);
        if (fx == fy) return;
        parent[fy] = fx;
        // 更新链表指针
        nxt[prev[fy]] = nxt[fy];
        prev[nxt[fy]] = prev[fy];
        // 合并额外信息
        val[fx] = combine(val[fx], val[fy]);
    }

    // 跳过已处理区间（常用操作）
    void skip(int l, int r) {
        for (int i = find(l); i <= r; i = find(nxt[i])) {
            merge(i, nxt[i]);
        }
    }
}

