// 线段树或其他数据结构类
class SegmentTree {
private:
    vector<Node> tree;
    int n;

    void build(int idx, int l, int r) {
        tree[idx].l = l; tree[idx].r = r;
        if (l == r) {
            // 初始化叶子节点
            return;
        }
        int mid = (l + r) / 2;
        build(idx*2, l, mid);
        build(idx*2+1, mid+1, r);
        tree[idx].merge(tree[idx*2], tree[idx*2+1]);
    }

    void push_down(int idx) {
        if (tree[idx].lazy) {
            // 下传懒标记到子节点
            // 更新子节点的信息和懒标记
            tree[idx].lazy = 0;
        }
    }

    void update(int idx, int ql, int qr, int val) {
        if (ql <= tree[idx].l && tree[idx].r <= qr) {
            // 更新当前节点信息，设置懒标记
            return;
        }
        push_down(idx);
        int mid = (tree[idx].l + tree[idx].r) / 2;
        if (ql <= mid) update(idx*2, ql, qr, val);
        if (qr > mid) update(idx*2+1, ql, qr, val);
        tree[idx].merge(tree[idx*2], tree[idx*2+1]);
    }

    Node query(int idx, int ql, int qr) {
        if (ql <= tree[idx].l && tree[idx].r <= qr) {
            return tree[idx];
        }
        push_down(idx);
        int mid = (tree[idx].l + tree[idx].r) / 2;
        if (qr <= mid) return query(idx*2, ql, qr);
        if (ql > mid) return query(idx*2+1, ql, qr);
        Node left = query(idx*2, ql, qr);
        Node right = query(idx*2+1, ql, qr);
        Node res;
        res.merge(left, right);
        return res;
    }

public:
    SegmentTree(int size) : n(size) {
        tree.resize(4 * n);
        build(1, 1, n);
    }

    void update(int l, int r, int val) {
        update(1, l, r, val);
    }

    int query(int l, int r) {
        return query(1, l, r).cnt;
    }
};

