// 可持久化数据结构通用模板框架
class PersistentDS {
    // 节点结构体，通常包含：
    // 1. 数据域（值、区间信息等）
    // 2. 指针域（左右子节点、版本指针等）
    struct Node {
        int val, lazy;
        int left, right;
        Node() : val(0), lazy(0), left(-1), right(-1) {}
    };

    vector<Node> nodes;  // 所有版本的节点池
    vector<int> roots;   // 各版本的根节点索引

    // 构造函数：初始化第0个版本（空版本）
    PersistentDS() {
        nodes.emplace_back();  // 空节点
        roots.push_back(0);    // 版本0的根
    }

    // 核心：克隆节点（创建新版本的关键）
    int clone(int idx) {
        nodes.push_back(nodes[idx]);
        return nodes.size() - 1;
    }

    // 更新操作（以线段树为例）
    int update(int prevRoot, int l, int r, int ql, int qr, int val) {
        int newRoot = clone(prevRoot);
        _update(newRoot, l, r, ql, qr, val);
        return newRoot;
    }

    void _update(int idx, int l, int r, int ql, int qr, int val) {
        if (ql <= l && r <= qr) {
            // 区间更新逻辑
            nodes[idx].val += (r - l + 1) * val;
            nodes[idx].lazy += val;
            return;
        }
        int mid = (l + r) >> 1;

        // 惰性传播时也需要克隆子节点
        if (nodes[idx].lazy) {
            nodes[idx].left = clone(nodes[idx].left);
            nodes[idx].right = clone(nodes[idx].right);
            _pushdown(idx, l, r);
        }

        if (ql <= mid) {
            nodes[idx].left = clone(nodes[idx].left);
            _update(nodes[idx].left, l, mid, ql, qr, val);
        }
        if (qr > mid) {
            nodes[idx].right = clone(nodes[idx].right);
            _update(nodes[idx].right, mid + 1, r, ql, qr, val);
        }
        _pushup(idx);
    }

    // 查询操作（不修改版本）
    int query(int version, int l, int r, int ql, int qr) {
        return _query(roots[version], l, r, ql, qr);
    }

    int _query(int idx, int l, int r, int ql, int qr) {
        if (ql <= l && r <= qr) return nodes[idx].val;
        int mid = (l + r) >> 1, res = 0;
        _pushdown(idx, l, r);
        if (ql <= mid) res += _query(nodes[idx].left, l, mid, ql, qr);
        if (qr > mid) res += _query(nodes[idx].right, mid + 1, r, ql, qr);
        return res;
    }

    void _pushdown(int idx, int l, int r) { /* 惰性传播 */ }
    void _pushup(int idx) { /* 向上更新 */ }

    // 创建新版本（基于旧版本进行修改）
    void newVersion(int baseVersion, /* 更新参数 */) {
        int newRoot = update(roots[baseVersion], ...);
        roots.push_back(newRoot);
    }

    // 回滚到历史版本（题目5的undo操作）
    void rollback(int targetVersion) {
        roots.push_back(roots[targetVersion]);
    }
};

// 可持久化字典树模板（题目1）
class PersistentTrie {
    struct Node {
        int next[26];
        int cnt;  // 子树大小
        Node() {
            memset(next, -1, sizeof(next));
            cnt = 0;
        }
    };
    vector<Node> nodes;
    vector<int> roots;

    int insert(int prevRoot, const string &s) {
        int newRoot = clone(prevRoot);
        int cur = newRoot;
        for (char c : s) {
            int idx = c - 'a';
            nodes[cur].next[idx] = clone(nodes[cur].next[idx]);
            cur = nodes[cur].next[idx];
            nodes[cur].cnt++;
        }
        return newRoot;
    }
};

// 可持久化并查集模板（带版本回退）
class PersistentDSU {
    vector<int> parent, size;
    vector<vector<pair<int, int>>> history;  // 修改记录

    void persistChange(int x, int oldVal) {
        history.back().emplace_back(x, oldVal);
    }

    void checkpoint() {
        history.emplace_back();
    }

    void rollback() {
        for (auto [x, val] : history.back()) {
            parent[x] = val;
        }
        history.pop_back();
    }
};

// 线段树模板（区间查询，区间更新）
class SegmentTree {
    int n;
    vector<int> tree, lazy;
    void build(int node, int l, int r, vector<int>& arr) {
        if (l == r) { tree[node] = arr[l]; return; }
        int mid = (l + r) / 2;
        build(node*2, l, mid, arr);
        build(node*2+1, mid+1, r, arr);
        tree[node] = tree[node*2] + tree[node*2+1]; // 根据问题修改合并操作
    }
    void push(int node, int l, int r) {
        if (lazy[node] != 0) {
            tree[node] += (r - l + 1) * lazy[node]; // 根据问题修改更新方式
            if (l != r) {
                lazy[node*2] += lazy[node];
                lazy[node*2+1] += lazy[node];
            }
            lazy[node] = 0;
        }
    }
    void update(int node, int l, int r, int ql, int qr, int val) {
        push(node, l, r);
        if (ql > r || qr < l) return;
        if (ql <= l && r <= qr) {
            lazy[node] += val;
            push(node, l, r);
            return;
        }
        int mid = (l + r) / 2;
        update(node*2, l, mid, ql, qr, val);
        update(node*2+1, mid+1, r, ql, qr, val);
        tree[node] = tree[node*2] + tree[node*2+1]; // 根据问题修改合并操作
    }
    int query(int node, int l, int r, int ql, int qr) {
        push(node, l, r);
        if (ql > r || qr < l) return 0; // 根据问题修改默认值
        if (ql <= l && r <= qr) return tree[node];
        int mid = (l + r) / 2;
        return query(node*2, l, mid, ql, qr) + query(node*2+1, mid+1, r, ql, qr); // 根据问题修改合并操作
    }
public:
    SegmentTree(vector<int>& arr) {
        n = arr.size();
        tree.resize(4*n);
        lazy.resize(4*n, 0);
        build(1, 0, n-1, arr);
    }
    void update(int l, int r, int val) { update(1, 0, n-1, l, r, val); }
    int query(int l, int r) { return query(1, 0, n-1, l, r); }
};

// 树状数组模板（单点更新，前缀查询）
class FenwickTree {
    int n;
    vector<int> bit;
public:
    FenwickTree(int n) : n(n), bit(n+1, 0) {}
    void add(int idx, int delta) {
        for (; idx <= n; idx += idx & -idx) bit[idx] += delta;
    }
    int sum(int idx) {
        int res = 0;
        for (; idx > 0; idx -= idx & -idx) res += bit[idx];
        return res;
    }
    int rangeSum(int l, int r) { return sum(r) - sum(l-1); }
};

